mapper.select:
SELECT E.user_id , E.employee_code , E.employee_name , E.myself , EC.support_type , EC.special_checkup , CC.reserve_date_begin , CC.reserve_date_end , CC.checkup_date_begin , CC.checkup_date_end , R.reservation_id , R.reservation_state , R.desired_at , R.checkuped_at , R.confirmed_at , CCT.company_checkup_type_code , CCT.company_checkup_type_name , CCST.sub_type_name , HCV.hospital_center_name , HCV.preday FROM employee E JOIN employee_checkup EC ON E.user_id = EC.user_id JOIN company_checkup CC ON EC.company_checkup_id = CC.company_checkup_id AND CC.checkup_year = #{checkupYear} JOIN company_checkup_type CCT ON EC.company_checkup_type_id = CCT.company_checkup_type_id LEFT JOIN reservation R ON EC.employee_checkup_id = R.employee_checkup_id AND (R.reservation_state != 0 OR R.confirmed_at IS NULL) LEFT JOIN checkup_contract_sub_type CCST ON R.checkup_contract_sub_type_id = CCST.checkup_contract_sub_type_id LEFT JOIN checkup_contract_type CCT2 ON CCST.checkup_contract_type_id = CCT2.checkup_contract_type_id LEFT JOIN hospital_center_view HCV ON CCT2.center_id = HCV.center_id WHERE E.company_id = #{companyId} AND E.employee_code = #{employeeCode}
AND E.user_id = #{userId}
ORDER BY E.myself DESC, EC.support_type, E.employee_name

mapper.update:
UPDATE reservation
   SET updated_at      = NOW()
     , updated_user_id = #{sessionUserId}
     , employee_notes  = #{employeeNotes}
 WHERE reservation_id = #{reservationId}

# UserReserveMapper.updateReserve
        UPDATE reservation
           SET confirmed_at                = NULL
             , updated_at                   = NOW()
             , updated_user_id              = #{sessionUserId}

             , checkup_contract_sub_type_id = #{checkupContractSubTypeId}


             , reservation_state            = #{reservationState}

             , canceled_at = NOW()
             , canceled_user_id             = #{sessionUserId}



             , reservation_name             = #{reservationNameCrypt}


             , birth                        = #{birth}


             , sex                          = #{sex}


             , email                        = #{email}


             , mobile                       = #{mobile}


             , zipcode                      = #{zipcode}


             , address1                     = #{address1}


             , address2                     = #{address2}


             , employee_notes               = #{employeeNotes}


             , hospital_notes               = #{hospitalNotes}


             , platform_notes               = #{platformNotes}


             , upgrade_pay                  = #{upgradePay}


             , support_pay                  = #{supportPay}


             , copay                        = #{copay}


             , hospital_pay                 = #{hospitalPay}


             , platform_pay                 = #{platformPay}


             , sum_item_copay               = #{sumItemCopay}


             , sum_item_discount_bill       = #{sumItemDiscountBill}


             , desired_at                   = #{desiredAt}

         WHERE reservation_id = #{reservationId}
           AND reservation_state != 0

mapper.select:
# UserReserveMapper.selectCenterList SELECT CCST.checkup_contract_sub_type_id , CCST.sub_type_name , HCV.hospital_center_name , HCV.center_id , HCV.address1 , HCV.address2 , HCV.advertisement , HCV.center_adv_filename1 FROM employee_checkup EC JOIN company_checkup CC on EC.company_checkup_id = CC.company_checkup_id JOIN checkup_contract_type CCT ON EC.company_checkup_type_id = CCT.company_checkup_type_id JOIN hospital_center_view HCV ON CCT.center_id = HCV.center_id JOIN checkup_contract_sub_type CCST ON CCT.checkup_contract_type_id = CCST.checkup_contract_type_id
JOIN ( SELECT CCI.checkup_contract_sub_type_id, COUNT(*) FROM checkup_contract_item CCI JOIN item I ON CCI.item_id = I.item_id WHERE CCI.deleted_at IS NULL AND I.deleted_at IS NULL AND I.no_use = '0' AND CCI.register != '0' AND CCI.item_id IN
#{itemId}
GROUP BY CCI.checkup_contract_sub_type_id HAVING COUNT(*) >= ${itemIdList.size} ) T ON T.checkup_contract_sub_type_id = CCST.checkup_contract_sub_type_id
WHERE CCST.deleted_at IS NULL AND EC.deleted_at IS NULL AND EC.user_id = #{userId}
AND HCV.sido = #{sido}
AND HCV.sigungu = #{sigungu}
AND HCV.able_special = 1
AND HCV.hospital_center_name LIKE CONCAT('%', #{centerName}, '%')
AND HCV.center_id NOT IN ( SELECT DISTINCT center_id FROM day_off WHERE day_off = DATE(#{desiredAt}) AND am_pm = #{desiredAmpm} ) AND DATE_ADD(DATE(NOW()), INTERVAL HCV.preday DAY) <= DATE(#{desiredAt})
AND CC.checkup_year = 2022 ORDER BY HCV.hospital_center_name
